using namespace std;

#define int long long

int32_t main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, k;
    cin>>n>>k;
    int indices[k];
    for (int i = 0; i < k; ++i) cin>>indices[i];

    function<bool(int, int)> solve = [&](int current, int other_ks) {
        if (!other_ks) return true;

        bool result = false;
        for (int i = 0; i < n; ++i) {
            if (!is_conflicting(current, i, other_ks - 1))
                result = result || solve(i, other_ks - 1);
        }
        return result;
    };

    function<bool(int, int)> is_conflicting = [&](int i, int queen, int other_ks) {
        return i == queen || abs(i / n - queen / n) == abs(i % n - queen % n);
    };

